mapper.delete:
DELETE FROM member_quiz_response
 WHERE member_id = #{memberId}
   AND quiz_id = #{questionId}

mapper.insert:
INSERT INTO point_history (point, description, member_id)
SELECT #{point}, CONCAT(#{questionId}, '_', #{memberId}), #{memberId}
 WHERE NOT EXISTS (
           SELECT 1
             FROM point_history
            WHERE member_id = #{memberId}
              AND description = CONCAT(#{questionId}, '_', #{memberId})
       )

mapper.update:
UPDATE member
   SET point = point + #{point}
 WHERE member_id = #{memberId}
